function riskyOp() {
  throw new Error('Что-то сломалось')
}

function process() {
  try {
    console.log('1: до ошибки')
    riskyOp()
    console.log('2: после ошибки')
  } catch (error) {
    console.log('3: в catch:', error.message)
  } finally {
    console.log('4: в finally')
  }
  console.log('5: после try/catch')
}

process()
